#!/usr/bin/env python3
"""
plot_profile.py — TBox 应用资源画像 HTML 生成器 (内嵌 csv_verify)
用法: python3 plot_profile.py <profile_dir>
"""
import sys, os, csv, subprocess, base64

_CSV_B64 = """"""

def _get_csv_verify():
    cache = '/tmp/.tbox_csv_verify_cached'
    try:
        b64 = _CSV_B64.strip()
        if len(b64) < 100: raise ValueError('not embedded')
        binary = base64.b64decode(b64)
        if os.path.exists(cache) and os.path.getsize(cache) == len(binary):
            return cache
        with open(cache, 'wb') as f: f.write(binary)
        os.chmod(cache, 0o755)
        return cache
    except:
        return os.path.join(os.path.dirname(os.path.abspath(__file__)),
                            '..', 'src', 'build', 'csv_verify')
CSV_VERIFY_BIN = _get_csv_verify()

EXPECTED_VERSION = "26.0.1"

def check_csv_version(profile_dir):
    """读取所有 CSV 的 # VERSION: 行, 逐文件比对期望版本。返回 None=全部一致, str=警告"""
    try:
        mismatched = []
        no_ver = []
        for fn in sorted(os.listdir(profile_dir)):
            if not fn.endswith('.csv'):
                continue
            path = os.path.join(profile_dir, fn)
            with open(path) as f:
                for line in f:
                    if line.startswith('# VERSION:'):
                        ver = line.split(':')[1].strip()
                        if ver != EXPECTED_VERSION:
                            mismatched.append((fn, ver))
                        break
                else:
                    no_ver.append(fn)
        if mismatched:
            detail = ', '.join(f'{f}(v{ver})' for f, ver in mismatched[:3])
            if len(mismatched) > 3:
                detail += f' ... 等{len(mismatched)}个文件'
            return f"版本不匹配 ({detail} — 绘图 v{EXPECTED_VERSION})"
        if no_ver:
            detail = ', '.join(no_ver[:3])
            if len(no_ver) > 3:
                detail += f' ... 等{len(no_ver)}个文件'
            return f"缺少版本号 (旧格式: {detail})"
    except Exception:
        pass
    return None

def verify_csv_signature(path):
    try:
        r = subprocess.run([CSV_VERIFY_BIN, '-q', path], capture_output=True, timeout=5)
        if r.returncode == 0:   return True, None
        elif r.returncode == 2: return None, None
        else:                   return False, r.stderr.decode().strip() or "签名验证失败"
    except FileNotFoundError: return 'no_binary', None
    except Exception as e:    return None, str(e)

def read_csv(path):
    rows = []
    with open(path, 'r') as f:
        for line in f:
            line = line.strip()
            if not line or line.startswith('#'): continue
            parts = line.split(',')
            try: rows.append(float(parts[1]) if len(parts)>1 else float(parts[0]))
            except (ValueError, IndexError): pass
    return rows

def read_csv_multi(path):
    """读取多列 CSV, 返回列列表的列表 [[col0,...], [col1,...], ...]"""
    cols = []
    with open(path, 'r') as f:
        for line in f:
            line = line.strip()
            if not line or line.startswith('#'): continue
            parts = line.split(',')
            if parts[0] == 'sample' or parts[0] == 'sec':
                cols = [[] for _ in range(len(parts)-1)]
                continue
            try:
                for c in range(1, len(parts)):
                    cols[c-1].append(float(parts[c]))
            except (ValueError, IndexError): pass
    return cols

PALETTE = ['#58a6ff','#3fb950','#f0883e','#d2a8ff','#f85149','#f59e0b',
           '#79c0ff','#56d364','#e29b44','#bc8cff','#ff7b72','#f2cc60']

def svg_line_chart_multi(series_list, width, height, ylabel, labels=None, sig_ok=None):
    """多系列折线图 SVG — 每个核心一条线"""
    if not series_list or not series_list[0]:
        return f'<svg viewBox="0 0 {width} {height}" xmlns="http://www.w3.org/2000/svg"><rect x="0" y="0" width="{width}" height="{height}" fill="#161b22" rx="4"/><text x="{width//2}" y="{height//2}" text-anchor="middle" fill="#888">No data</text></svg>'

    all_y = [y for s in series_list for y in s]
    ymax = max(all_y) if all_y else 1
    if ymax <= 10:   ymax = int(ymax) + 1
    elif ymax <= 100: ymax = ((int(ymax)//10)+1)*10
    else:             ymax = ((int(ymax)//100)+1)*100
    if ymax == 0: ymax = 1

    ml, mr, mt, mb = 52, 20, 26, 32
    pw = width - ml - mr; ph = height - mt - mb
    def ty(y): return height - mb - (y / ymax) * ph

    n_labels = labels if labels else [f'Core {i}' for i in range(len(series_list))]

    # 网格 + Y 轴
    grid = ''.join(f'<line x1="{ml}" y1="{mt+ph*i/4:.1f}" x2="{width-mr}" y2="{mt+ph*i/4:.1f}" stroke="#333" stroke-dasharray="4,4"/>' for i in range(5))
    ylbl = ''.join(f'<text x="{ml-6}" y="{mt+ph*(4-i)/4+4:.1f}" text-anchor="end" fill="#888" font-size="10">{ymax*i/4:.0f}</text>' for i in range(5))

    # 每条线
    lines = ''
    for si, series in enumerate(series_list):
        if len(series) < 2: continue
        color = PALETTE[si % len(PALETTE)]
        n = len(series); gap = pw / max(1, n-1)
        pts = ' '.join(f'{ml+i*gap:.1f},{ty(y):.1f}' for i, y in enumerate(series))
        lines += f'<polyline points="{pts}" fill="none" stroke="{color}" stroke-width="2" stroke-linejoin="round"/>'

    # X labels
    n = len(series_list[0]); step = max(1, n//8)
    xlbl = ''.join(f'<text x="{ml+i*pw/max(1,n-1):.1f}" y="{height-mb+16}" text-anchor="middle" fill="#888" font-size="9">{i+1}</text>' for i in range(0, n, step))

    # Legend
    n_lbl = len(series_list)
    legend_bg = f'<rect x="{width-mr-62}" y="{mt-4}" width="62" height="{14*n_lbl+12}" fill="#161b22" rx="3"/>'
    legend = ''.join(f'<line x1="{width-mr-40}" y1="{mt+4+si*14+5}" x2="{width-mr-26}" y2="{mt+4+si*14+5}" stroke="{PALETTE[si%len(PALETTE)]}" stroke-width="2"/><text x="{width-mr-22}" y="{mt+4+si*14+5}" fill="#888" font-size="8">{n_labels[si]}</text>' for si in range(len(series_list)))

    sw = ''
    if sig_ok is False:
        sw = f'<rect x="0" y="0" width="{width}" height="22" fill="#f8514933" rx="0"/><text x="{width//2}" y="15" text-anchor="middle" fill="#f85149" font-size="11" font-weight="bold">⚠ 签名无效 — 数据可能被篡改</text>'
    elif sig_ok is None:
        sw = f'<rect x="0" y="0" width="{width}" height="22" fill="#d2991d33" rx="0"/><text x="{width//2}" y="15" text-anchor="middle" fill="#d2991d" font-size="11" font-weight="bold">⚠ 无签名 — 无法核实真伪</text>'
    elif sig_ok == 'no_binary':
        sw = f'<rect x="0" y="0" width="{width}" height="22" fill="#d2991d33" rx="0"/><text x="{width//2}" y="15" text-anchor="middle" fill="#d2991d" font-size="11" font-weight="bold">⚠ 无法验签 — 验签工具未找到</text>'
    title_y = 36 if sw else 14
    return f'<svg viewBox="0 0 {width} {height}" xmlns="http://www.w3.org/2000/svg"><rect x="0" y="0" width="{width}" height="{height}" fill="#161b22" rx="4"/>{sw}<text x="{width//2}" y="{title_y}" text-anchor="middle" fill="#ccc" font-size="13" font-weight="bold">{ylabel}</text>{grid}{ylbl}{xlbl}<line x1="{ml}" y1="{height-mb}" x2="{width-mr}" y2="{height-mb}" stroke="#555" stroke-width="1"/><line x1="{ml}" y1="{mt}" x2="{ml}" y2="{height-mb}" stroke="#555" stroke-width="1"/>{lines}{legend_bg}{legend}</svg>'


def svg_bar_chart(data, width, height, color, ylabel, sig_ok=None):
    if not data:
        return f'<svg viewBox="0 0 {width} {height}" xmlns="http://www.w3.org/2000/svg"><rect x="0" y="0" width="{width}" height="{height}" fill="#161b22" rx="4"/><text x="{width//2}" y="{height//2}" text-anchor="middle" fill="#888">No data</text></svg>'
    ys = data
    ymax = max(ys); ymax = int(ymax)+1 if ymax<=10 else ((int(ymax)//10)+1)*10 if ymax<=100 else ((int(ymax)//100)+1)*100
    if ymax == 0: ymax = 1
    ml, mr, mt, mb = 52, 20, 38, 40
    pw = width - ml - mr; ph = height - mt - mb
    def ty(y): return height - mb - (y / ymax) * ph
    n = len(data); gap = pw / n; bar_w = max(2, gap / 1.5)
    bars = ''.join(f'<rect x="{ml+gap*i+(gap-bar_w)/2:.1f}" y="{ty(y):.1f}" width="{bar_w:.1f}" height="{max(1,ty(0)-ty(y)):.1f}" fill="{color}" opacity="0.8" rx="2"/>' for i,y in enumerate(ys))
    grid = ''.join(f'<line x1="{ml}" y1="{mt+ph*i/4:.1f}" x2="{width-mr}" y2="{mt+ph*i/4:.1f}" stroke="#333" stroke-dasharray="4,4"/>' for i in range(5))
    ylbl = ''.join(f'<text x="{ml-6}" y="{mt+ph*(4-i)/4+4:.1f}" text-anchor="end" fill="#888" font-size="10">{ymax*i/4:.0f}</text>' for i in range(5))
    xlbl = ''; step = max(1, n//8)
    for i in range(0, n, step):
        xlbl += f'<text x="{ml+gap*i+gap/2:.1f}" y="{height-mb+16}" text-anchor="middle" fill="#888" font-size="9">{i+1}</text>'
    warning = ''; title_y = 16
    if sig_ok is False:
        warning = f'<rect x="0" y="0" width="{width}" height="22" fill="#f8514933" rx="0"/><text x="{width//2}" y="15" text-anchor="middle" fill="#f85149" font-size="11" font-weight="bold">⚠ 签名无效 — 数据可能被篡改</text>'
        title_y = 36
    elif sig_ok is None:
        warning = f'<rect x="0" y="0" width="{width}" height="22" fill="#d2991d33" rx="0"/><text x="{width//2}" y="15" text-anchor="middle" fill="#d2991d" font-size="11" font-weight="bold">⚠ 无签名 — 无法核实真伪</text>'
        title_y = 36
    elif sig_ok == 'no_binary':
        warning = f'<rect x="0" y="0" width="{width}" height="22" fill="#d2991d33" rx="0"/><text x="{width//2}" y="15" text-anchor="middle" fill="#d2991d" font-size="11" font-weight="bold">⚠ 无法验签 — 验签工具未找到</text>'
        title_y = 36
    return f'<svg viewBox="0 0 {width} {height}" xmlns="http://www.w3.org/2000/svg"><rect x="0" y="0" width="{width}" height="{height}" fill="#161b22" rx="4"/><text x="{width//2}" y="{title_y}" text-anchor="middle" fill="#ccc" font-size="13" font-weight="bold">{ylabel}</text>{warning}{grid}{ylbl}{xlbl}<line x1="{ml}" y1="{height-mb}" x2="{width-mr}" y2="{height-mb}" stroke="#555" stroke-width="1"/><line x1="{ml}" y1="{mt}" x2="{ml}" y2="{height-mb}" stroke="#555" stroke-width="1"/>{bars}</svg>'

def build_html(profile_dir):
    proc_name = "unknown"
    rpt = os.path.join(profile_dir, "report.txt")
    if os.path.exists(rpt):
        for line in open(rpt):
            if "进程名称:" in line: proc_name = line.split(":")[-1].strip(); break
    csv_files = {'cpu':'cpu.csv','mem':'mem.csv','threads_fd':'threads_fd.csv','io':'io.csv','core':'core.csv','net':'net.csv'}
    sig = {}
    for k, fn in csv_files.items():
        fp = os.path.join(profile_dir, fn)
        sig[k] = verify_csv_signature(fp) if os.path.exists(fp) else (None, None)
    cpu_raw = read_csv(os.path.join(profile_dir,"cpu.csv"))
    mem_cols = read_csv_multi(os.path.join(profile_dir,"mem.csv"))
    mem_rss = mem_cols[0] if mem_cols else []
    mem_pss = mem_cols[1] if len(mem_cols) > 1 else []
    mem_uss = mem_cols[2] if len(mem_cols) > 2 else []
    thr_cols = read_csv_multi(os.path.join(profile_dir,"threads_fd.csv"))
    tr  = thr_cols[0] if thr_cols else []
    fd  = thr_cols[1] if len(thr_cols) > 1 else []
    io_cols = read_csv_multi(os.path.join(profile_dir,"io.csv"))
    ior = io_cols[0] if io_cols else []
    iow = io_cols[1] if len(io_cols) > 1 else []
    # core.csv: variable columns, read all
    core_cols = []
    core_path = os.path.join(profile_dir, "core.csv")
    if os.path.exists(core_path):
        core_data = read_csv_multi(core_path) if os.path.exists(core_path) else []
    w, h = 500, 260
    sf = lambda k: sig[k][0] if sig.get(k) else None
    # Per-core CPU chart (show all cores as average, or first core if only 1)
    core_chart = ''
    if core_data and len(core_data) > 0:
        n = len(core_data)
        label = 'Per-Core CPU (%)'
        if core_data:
            all_max = max(max(s) for s in core_data)
            label += f' — max: {all_max:.1f}'
        core_labels = [f'Core {i}' for i in range(n)]
        core_chart = svg_line_chart_multi(core_data, w, h, label, labels=core_labels, sig_ok=sf('core'))

    def label_with_max(data, base):
        return f'{base} — max: {max(data):.1f}' if data else base

    charts = [
        ('CPU (%)', svg_bar_chart(cpu_raw,w,h,'#58a6ff',label_with_max(cpu_raw,'CPU Usage (%)'),sig_ok=sf('cpu'))),
        ('Threads', svg_bar_chart(tr,w,h,'#f0883e',label_with_max(tr,'Thread Count'),sig_ok=sf('threads_fd'))),
        ('File Descriptors', svg_bar_chart(fd,w,h,'#d2a8ff',label_with_max(fd,'Open File Descriptors'),sig_ok=sf('threads_fd'))),
    ]
    panels = ''.join(f'<div class="chart-panel">{s}</div>' for _, s in charts)

    # Memory line chart (RSS + PSS + USS)
    if mem_rss and mem_pss and mem_uss:
        mx = lambda d: f'{max(d):.0f}' if d else '0'
        mem_label = f'Memory (KB) — max RSS:{mx(mem_rss)} PSS:{mx(mem_pss)} USS:{mx(mem_uss)}'
        mem_chart = svg_line_chart_multi([mem_rss, mem_pss, mem_uss], w, h,
                                          mem_label, labels=['RSS','PSS','USS'], sig_ok=sf('mem'))
        panels += f'<div class="chart-panel">{mem_chart}</div>'

    # IO line chart (Read + Write)
    if ior and iow:
        mx = lambda d: f'{max(d):.0f}' if d else '0'
        io_label = f'IO Throughput (KB/s) — max R:{mx(ior)} W:{mx(iow)}'
        io_chart = svg_line_chart_multi([ior, iow], w, h, io_label, labels=['Read','Write'], sig_ok=sf('io'))
        panels += f'<div class="chart-panel">{io_chart}</div>'

    # Network line chart
    net_path = os.path.join(profile_dir, 'net.csv')
    if os.path.exists(net_path):
        net_cols = read_csv_multi(net_path)
        if net_cols:
            with open(net_path) as f:
                hdr = f.readline().strip().split(',')
            all_ifaces = [(i, hdr[i+1]) for i in range(0, len(hdr)-1, 2)]
            if all_ifaces:
                net_series = [net_cols[i] for i, _ in all_ifaces]
                net_labels = [n for _, n in all_ifaces]
                all_max = max(max(s) for s in net_series) if net_series else 0
                net_chart = svg_line_chart_multi(net_series, w, h,
                                                  f'Network (KB/s) — max: {all_max:.0f}',
                                                  labels=net_labels, sig_ok=sf('net'))
                panels += f'<div class="chart-panel">{net_chart}</div>'

    if core_chart:
        panels += f'<div class="chart-panel">{core_chart}</div>'
    return f'<!DOCTYPE html><html lang="zh-CN"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>TBox Resource Profile v26.0.1 — {proc_name}</title><style>*{{box-sizing:border-box;margin:0;padding:0}}body{{background:#0d1117;color:#c9d1d9;font-family:-apple-system,BlinkMacSystemFont,"Microsoft YaHei",sans-serif;padding:24px 32px}}h1{{color:#f0f6fc;font-size:1.4rem;margin-bottom:4px}}.sub{{color:#8b949e;font-size:.85rem;margin-bottom:24px}}.grid{{display:grid;grid-template-columns:repeat(auto-fill,minmax(520px,1fr));gap:18px}}.chart-panel{{background:#161b22;border:1px solid #30363d;border-radius:8px;padding:12px}}.chart-panel svg{{width:100%;height:auto;display:block}}.footer{{text-align:center;color:#8b949e;font-size:.75rem;margin-top:30px;padding-top:16px;border-top:1px solid #30363d}}</style></head><body><h1>TBox Resource Profile v26.0.1 — {proc_name}</h1><p class="sub">Data source: {profile_dir}</p><div class="grid">{panels}</div><div class="footer"><p>Generated by plot_profile.py — TBox Resource Monitor Toolkit</p></div></body></html>'

if __name__ == '__main__':
    if len(sys.argv) == 2 and sys.argv[1] in ('-v', '--version'): print('plot_profile.py v26.0.1'); sys.exit(0)
    if len(sys.argv) < 2: print(f"用法: {sys.argv[0]} <profile_dir>"); sys.exit(1)
    d = sys.argv[1]
    if not os.path.isdir(d): print(f"❌ 目录不存在: {d}"); sys.exit(1)
    out = os.path.join(d, "chart.html")
    ver_warn = check_csv_version(d)
    html = build_html(d)
    if ver_warn:
        html = html.replace('<h1>', f'<p style="color:#f59e0b;font-size:12px;margin-bottom:8px">⚠ {ver_warn}</p>\n<h1>')
    open(out, 'w', encoding='utf-8').write(html)
    print(f"✅ 图表已生成: {out}")
